     1→import React, { useEffect, useRef, useState } from "react";
     2→import { useNavigate, useParams, useSearchParams, useLocation } from "react-router-dom";
     3→import { useBreadcrumb } from "../BreadcrumbContext";
     4→import { Center, Loader, Text, ScrollArea, Box, Badge, Group, UnstyledButton, Collapse, Checkbox, ActionIcon, Tooltip, Menu } from "@mantine/core";
     5→import {
     6→  fetchSession,
     7→  fetchLogEvents,
     8→  fetchSessionCheckpoints,
     9→  spawnSession,
    10→  updateOpenItemStatus,
    11→  subscribeToUpdates,
    12→  type Session,
    13→  type Event,
    14→  type SessionCheckpoint,
    15→  type OpenItem,
    16→  type LogEventItem,
    17→} from "../api";
    18→import { EventItem, type UserInfo } from "../components/EventItem";
    19→import { ToolGroupItem, type ToolUseData } from "../components/ToolGroupItem";
    20→import { MarkdownView } from "../components/MarkdownView";
    21→import { TimeAgo } from "../components/TimeAgo";
    22→import claudeLogo from "../assets/claude-logo.png";
    23→
    24→type DisplayItem =
    25→  | { kind: "event"; event: Event }
    26→  | { kind: "toolGroup"; tools: ToolUseData[] }
    27→  | { kind: "checkpoint"; checkpoint: SessionCheckpoint };
    28→
    29→type RenderItem =
    30→  | { kind: "event"; event: Event }
    31→  | { kind: "claudeTurn"; toolGroups: ToolUseData[][]; stop: Event | null }
    32→  | { kind: "checkpoint"; checkpoint: SessionCheckpoint };
    33→
    34→function groupClaudeTurns(items: DisplayItem[]): RenderItem[] {
    35→  const result: RenderItem[] = [];
    36→  let i = 0;
    37→  while (i < items.length) {
    38→    const item = items[i];
    39→    if (item.kind === "toolGroup") {
    40→      const toolGroups: ToolUseData[][] = [];
    41→      while (i < items.length && items[i].kind === "toolGroup") {
    42→        toolGroups.push((items[i] as { kind: "toolGroup"; tools: ToolUseData[] }).tools);
    43→        i++;
    44→      }
    45→      let stop: Event | null = null;
    46→      if (i < items.length && items[i].kind === "event" && (items[i] as { kind: "event"; event: Event }).event.event === "Stop") {
    47→        stop = (items[i] as { kind: "event"; event: Event }).event;
    48→        i++;
    49→      }
    50→      result.push({ kind: "claudeTurn", toolGroups, stop });
    51→    } else if (item.kind === "event" && item.event.event === "Stop") {
    52→      result.push({ kind: "claudeTurn", toolGroups: [], stop: item.event });
    53→      i++;
    54→    } else if (item.kind === "checkpoint") {
    55→      result.push({ kind: "checkpoint", checkpoint: item.checkpoint });
    56→      i++;
    57→    } else {
    58→      result.push({ kind: "event", event: (item as { kind: "event"; event: Event }).event });
    59→      i++;
    60→    }
    61→  }
    62→  return result;
    63→}
    64→
    65→function str(v: unknown): string { return typeof v === "string" ? v : ""; }
    66→
    67→function highlightText(text: string, terms: string[]): React.ReactNode {
    68→  if (!terms.length) return text;
    69→  const pattern = terms.map((t) => t.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")).join("|");
    70→  const parts = text.split(new RegExp(`(${pattern})`, "gi"));
    71→  return (
    72→    <>
    73→      {parts.map((p, i) =>
    74→        i % 2 === 1
    75→          ? <mark key={i} style={{ background: "rgba(255,200,0,0.45)", borderRadius: 2, padding: "0 1px" }}>{p}</mark>
    76→          : p
    77→      )}
    78→    </>
    79→  );
    80→}
    81→
    82→function ClaudeTurnCard({ toolGroups, stop, isTarget, matchTerms, expandTools, expandThinking, targetLogEventId }: {
    83→  toolGroups: ToolUseData[][];
    84→  stop: Event | null;
    85→  isTarget?: boolean;
    86→  matchTerms?: string[];
    87→  expandTools?: boolean;
    88→  expandThinking?: boolean;
    89→  targetLogEventId?: number | null;
    90→}) {
    91→  const d = stop ? (stop.data ?? {}) as Record<string, unknown> : {};
    92→  const msg = str(d.last_assistant_message);
    93→  const thinking = str(d.thinking);
    94→  const reason = str(d.reason);
    95→  const thinkingLogEventId = typeof d.thinkingLogEventId === "number" ? d.thinkingLogEventId : null;
    96→  const thinkingUuid = typeof d.thinkingUuid === "string" ? d.thinkingUuid : null;
    97→  const toolsLogEventId = typeof d.toolsLogEventId === "number" ? d.toolsLogEventId : null;
    98→  const toolsUuid = typeof d.toolsUuid === "string" ? d.toolsUuid : null;
    99→  const [toolsExpanded, setToolsExpanded] = useState(false);
   100→  const [thinkingExpanded, setThinkingExpanded] = useState(false);
   101→  const totalTools = toolGroups.reduce((n, g) => n + g.length, 0);
   102→
   103→  useEffect(() => {
   104→    if (expandThinking && thinking) setThinkingExpanded(true);
   105→  }, [expandThinking, thinking]);
   106→
   107→  useEffect(() => {
   108→    if (expandTools && totalTools > 0) setToolsExpanded(true);
   109→  }, [expandTools, totalTools]);
   110→
   111→  return (
   112→    <Box style={{ display: "flex", padding: "12px 20px 4px", gap: 10 }}>
   113→      <img src={claudeLogo} alt="Claude" style={{ width: 28, height: 28, borderRadius: "50%", flexShrink: 0, marginTop: 2 }} />
   114→      <Box style={{ flex: 1, minWidth: 0 }}>
   115→        <Group gap={8} mb={6} align="center">
   116→          <Text size="xs" fw={600} c="orange">Claude</Text>
   117→          {reason && <Badge color="orange" size="xs" variant="light">{reason}</Badge>}
   118→          {stop && <TimeAgo iso={stop.timestamp} />}
   119→        </Group>
   120→        {thinking && (
   121→          <Box mb={6} id={thinkingUuid ?? (thinkingLogEventId != null ? `log-event-${thinkingLogEventId}` : undefined)}>
   122→            <Group
   123→              gap={6}
   124→              mb={4}
   125→              style={{ cursor: "pointer" }}
   126→              onClick={() => setThinkingExpanded((v) => !v)}
   127→            >
   128→              <Text size="xs" c="dimmed" fs="italic">thinking {thinkingExpanded ? "▲" : "▼"}</Text>
   129→            </Group>
   130→            <Collapse in={thinkingExpanded}>
   131→              <Box style={{
   132→                backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-7))",
   133→                border: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-5))",
   134→                borderRadius: 8,
   135→                padding: "10px 14px",
   136→                fontFamily: "monospace",
   137→                fontSize: 12,
   138→                lineHeight: 1.6,
   139→                whiteSpace: "pre-wrap",
   140→                wordBreak: "break-word",
   141→                color: "light-dark(var(--mantine-color-gray-7), var(--mantine-color-gray-4))",
   142→              }}>
   143→                {highlightText(thinking, matchTerms ?? [])}
   144→              </Box>
   145→            </Collapse>
   146→          </Box>
   147→        )}
   148→        {stop && msg && (
   149→          <Box style={{
   150→            backgroundColor: "light-dark(var(--mantine-color-white), var(--mantine-color-dark-6))",
   151→            border: "1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-4))",
   152→            borderRadius: "2px 14px 14px 14px",
   153→            padding: "12px 16px",
   154→            marginBottom: toolGroups.length > 0 ? 8 : 0,
   155→          }}>
   156→            <MarkdownView text={msg} highlightTerms={matchTerms} />
   157→          </Box>
   158→        )}
   159→        {toolGroups.length > 0 && (
   160→          <Box id={toolsUuid ?? (toolsLogEventId != null ? `log-event-${toolsLogEventId}` : undefined)}>
   161→            <Group
   162→              gap={6}
   163→              mb={4}
   164→              style={{ cursor: "pointer" }}
   165→              onClick={() => setToolsExpanded((v) => !v)}
   166→            >
   167→              <Text size="xs" c="dimmed">
   168→                {totalTools} tool {totalTools === 1 ? "use" : "uses"}
   169→              </Text>
   170→              <Text size="xs" c="dimmed">{toolsExpanded ? "▲" : "▼"}</Text>
   171→            </Group>
   172→            <Collapse in={toolsExpanded}>
   173→              <Box style={{ display: "flex", flexDirection: "column", gap: 4 }}>
   174→                {toolGroups.map((tools, i) => (
   175→                  <ToolGroupItem key={i} tools={tools} autoExpand={expandTools} matchTerms={matchTerms} targetLogEventId={expandTools ? targetLogEventId : null} />
   176→                ))}
   177→              </Box>
   178→            </Collapse>
   179→          </Box>
   180→        )}
   181→      </Box>
   182→    </Box>
   183→  );
   184→}
   185→
   186→// TODO: we're dropping the UUIDs from LogEventItems, or at least mixing them up into currentTurnLogEventIds.
   187→// We need to attach these UUIDs to the components that these generate. That way the scrolling will work.
   188→/**
   189→ * Convert LogEventItems (from full.jsonl tables) into pseudo-Event objects that
   190→ * match the shape the existing UI components expect.  This lets all downstream
   191→ * grouping and rendering code remain unchanged.
   192→ */
   193→function logEventsToEvents(logEvents: LogEventItem[]): Event[] {
   194→  const result: Event[] = [];
   195→  let id = -1;
   196→  let lastAssistantText: string | null = null;
   197→  let lastAssistantThinking: string | null = null;
   198→  let lastAssistantLogEventId: number | null = null;
   199→  let lastThinkingLogEventId: number | null = null;
   200→  let lastThinkingUuid: string | null = null;
   201→  let lastToolsLogEventId: number | null = null;
   202→  let lastToolsUuid: string | null = null;
   203→  // All LogEvent IDs seen in the current assistant turn (thinking, text, tool_use may be separate events)
   204→  const currentTurnLogEventIds: number[] = [];
   205→
   206→  // TODO: look at which event types are useful.
   207→  const filtered = logEvents.filter(
   208→    (e) => !e.isSidechain && e.type !== "file-history-snapshot" && e.type !== "progress",
   209→  );
   210→
   211→  // Virtual SessionStart divider
   212→  const first = filtered[0];
   213→  if (first) {
   214→    result.push({ id: id--, timestamp: first.timestamp ?? "", event: "SessionStart", sessionId: first.sessionId ?? "", blocked: false, data: { cwd: first.cwd ?? "" }, summary: null, keywords: [], _sourceLogEventId: first.id });
   215→  }
   216→
   217→  for (const le of filtered) {
   218→    const ts  = le.timestamp ?? "";
   219→    const sid = le.sessionId ?? "";
   220→
   221→    if (le.type === "user") {
   222→      const toolResults = le.contents.filter((c) => c.contentType === "tool_result");
   223→      // TODO: show images and other content types
   224→      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
   225→
   226→      if (toolResults.length > 0) {
   227→        for (const tr of toolResults) {
   228→          const failed = tr.isError === true;
   229→          result.push({
   230→            id: id--,
   231→            timestamp: ts,
   232→            event: failed ? "PostToolUseFailure" : "PostToolUse",
   233→            sessionId: sid,
   234→            blocked: false,
   235→            data: {
   236→              tool_use_id:   tr.toolUseId,
   237→              tool_response: !failed ? (tr.toolResultContent ?? "") : undefined,
   238→              error:          failed ? (tr.toolResultContent ?? "") : undefined,
   239→            },
   240→            summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   241→          });
   242→        }
   243→      } else if (textBlocks.length > 0) {
   244→        const prompt = textBlocks.map((b) => b.text ?? "").join("\n\n");
   245→        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
   246→      }
   247→
   248→    } else if (le.type === "assistant") {
   249→      const toolUses      = le.contents.filter((c) => c.contentType === "tool_use");
   250→      const textBlocks    = le.contents.filter((c) => c.contentType === "text");
   251→      const thinkingBlocks = le.contents.filter((c) => c.contentType === "thinking");
   252→
   253→      // Track all LogEvent IDs in this turn so thinking-only events are reachable
   254→      if (!currentTurnLogEventIds.includes(le.id)) currentTurnLogEventIds.push(le.id);
   255→
   256→      if (textBlocks.length > 0) {
   257→        lastAssistantText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
   258→        lastAssistantLogEventId = le.id;
   259→      }
   260→      if (thinkingBlocks.length > 0) {
   261→        const thinking = thinkingBlocks.map((b) => b.thinking ?? "").filter(Boolean).join("\n\n");
   262→        lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + thinking : thinking;
   263→        lastThinkingLogEventId = le.id;
   264→        lastThinkingUuid = le.uuid ?? null;
   265→        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
   266→      }
   267→
   268→      for (const tu of toolUses) {
   269→        lastToolsLogEventId = le.id;
   270→        lastToolsUuid = le.uuid ?? null;
   271→        result.push({
   272→          id: id--,
   273→          timestamp: ts,
   274→          event: "PreToolUse",
   275→          sessionId: sid,
   276→          blocked: false,
   277→          data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput },
   278→          summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined,
   279→        });
   280→      }
   281→
   282→    } else if (le.type === "system" && le.systemData?.subtype === "stop_hook_summary") {
   283→      const primaryId = lastAssistantLogEventId ?? le.id;
   284→      const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   285→      result.push({
   286→        id: id--,
   287→        timestamp: ts,
   288→        event: "Stop",
   289→        sessionId: sid,
   290→        blocked: le.systemData.preventedContinuation ?? false,
   291→        data: {
   292→          last_assistant_message: lastAssistantText ?? "",
   293→          thinking: lastAssistantThinking ?? "",
   294→          reason: le.systemData.stopReason ?? "",
   295→          thinkingLogEventId: lastThinkingLogEventId ?? undefined,
   296→          thinkingUuid: lastThinkingUuid ?? undefined,
   297→          toolsLogEventId: lastToolsLogEventId ?? undefined,
   298→          toolsUuid: lastToolsUuid ?? undefined,
   299→        },
   300→        summary: null, keywords: [],
   301→        _sourceLogEventId: primaryId,
   302→        _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   303→      });
   304→      lastAssistantText = null;
   305→      lastAssistantThinking = null;
   306→      lastAssistantLogEventId = null;
   307→      lastThinkingLogEventId = null;
   308→      lastThinkingUuid = null;
   309→      lastToolsLogEventId = null;
   310→      lastToolsUuid = null;
   311→      currentTurnLogEventIds.length = 0;
   312→    }
   313→  }
   314→
   315→  // Flush any trailing assistant text that had no stop event
   316→  if (lastAssistantText !== null && filtered.length > 0) {
   317→    const last = filtered[filtered.length - 1];
   318→    const primaryId = lastAssistantLogEventId ?? last.id;
   319→    const extraIds = currentTurnLogEventIds.filter((x) => x !== primaryId);
   320→    result.push({
   321→      id: id--,
   322→      timestamp: last.timestamp ?? "",
   323→      event: "Stop",
   324→      sessionId: last.sessionId ?? "",
   325→      blocked: false,
   326→      data: { last_assistant_message: lastAssistantText, thinking: lastAssistantThinking ?? "", reason: "" },
   327→      summary: null, keywords: [],
   328→      _sourceLogEventId: primaryId,
   329→      _extraSourceLogEventIds: extraIds.length > 0 ? extraIds : undefined,
   330→    });
   331→  }
   332→
   333→  return result;
   334→}
   335→
   336→function groupEvents(events: Event[]): DisplayItem[] {
   337→  const postMap = new Map<string, Event>();
   338→  for (const event of events) {
   339→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   340→      const d = event.data as Record<string, unknown>;
   341→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   342→      if (id) postMap.set(id, event);
   343→    }
   344→  }
   345→
   346→  type RawItem =
   347→    | { kind: "event"; event: Event }
   348→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
   349→
   350→  const raw: RawItem[] = [];
   351→  const consumed = new Set<number>();
   352→
   353→  for (const event of events) {
   354→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   355→    if (event.event === "PreToolUse") {
   356→      const d = event.data as Record<string, unknown>;
   357→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   358→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   359→      if (post) consumed.add(post.id);
   360→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   361→      continue;
   362→    }
   363→    raw.push({ kind: "event", event });
   364→  }
   365→
   366→  const isGroupable = (item: RawItem) =>
   367→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   368→
   369→  const result: DisplayItem[] = [];
   370→  let i = 0;
   371→  while (i < raw.length) {
   372→    if (isGroupable(raw[i])) {
   373→      const group: ToolUseData[] = [];
   374→      while (i < raw.length && isGroupable(raw[i])) {
   375→        const item = raw[i];
   376→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   377→        i++;
   378→      }
   379→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   380→    } else {
   381→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   382→      i++;
   383→    }
   384→  }
   385→  return result;
   386→}
   387→
   388→function CheckpointRow({ checkpoint, onPress }: { checkpoint: SessionCheckpoint; onPress: () => void }) {
   389→  const [expanded, setExpanded] = useState(false);
   390→  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;
   391→  const fileCount = checkpoint.filesTouched.length;
   392→  const sum = checkpoint.summary;
   393→
   394→  return (
   395→    <Box style={{ padding: "4px 20px 4px 58px" }}>
   396→    <Box style={{ borderLeft: "4px solid var(--mantine-color-teal-6)", borderRadius: 8, overflow: "hidden" }}>
   397→      <UnstyledButton
   398→        onClick={() => setExpanded((v) => !v)}
   399→        style={{ width: "100%", display: "flex", alignItems: "center", gap: 10, padding: "8px 12px", backgroundColor: "light-dark(var(--mantine-color-teal-0), var(--mantine-color-dark-6))" }}
   400→      >
   401→        <Box style={{ flex: 1 }}>
   402→          <Group gap={8} mb={2}>
   403→            <Text size="xs" fw={700} c="teal" tt="uppercase">Checkpoint</Text>
   404→            <Text ff="monospace" size="xs" c="green" fw={600}>{checkpoint.checkpointId}</Text>
   405→            {checkpoint.branch && <Badge variant="light" color="teal" size="xs">{checkpoint.branch}</Badge>}
   406→          </Group>
   407→          {sum?.intent && (
   408→            <Text size="xs" c="dimmed" fs="italic" lineClamp={expanded ? undefined : 1}>{sum.intent}</Text>
   409→          )}
   410→        </Box>
   411→        <Box style={{ textAlign: "right", flexShrink: 0 }}>
   412→          {fileCount > 0 && <Text size="xs" c="dimmed" ff="monospace">{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>}
   413→          {outTokens > 0 && <Text size="xs" c="dimmed" ff="monospace">{outTokens.toLocaleString()} tok</Text>}
   414→        </Box>
   415→      </UnstyledButton>
   416→
   417→      <Collapse in={expanded}>
   418→        <Box style={{ backgroundColor: "light-dark(var(--mantine-color-teal-0), var(--mantine-color-dark-7))", borderTop: "1px solid var(--mantine-color-teal-2)", padding: "12px 16px", display: "flex", flexDirection: "column", gap: 8 }}>
   419→          {sum?.outcome && (
   420→            <Box>
   421→              <Text size="xs" fw={700} c="dimmed" tt="uppercase" mb={2}>✓ Outcome</Text>
   422→              <Text size="xs">{sum.outcome}</Text>
   423→            </Box>
   424→          )}
   425→          {sum?.repoLearnings?.length ? (
