   528→  const [items, setItems] = useState<RenderItem[]>([]);
   529→  const [userInfo, setUserInfo] = useState<UserInfo | undefined>(undefined);
   530→  const [openItems, setOpenItems] = useState<OpenItem[]>([]);
   531→  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
   532→  const [spawning, setSpawning] = useState(false);
   533→  const [loading, setLoading] = useState(true);
   534→  const [error, setError] = useState<string | null>(null);
   535→
   536→  const id = sessionId!;
