   538→
   539→  function applyCheckpoints(logEvs: LogEventItem[], checkpoints: SessionCheckpoint[]) {
   540→    const grouped = groupEvents(logEventsToEvents(logEvs));
   541→    const merged: DisplayItem[] = [];
   542→    let cpIdx = 0;
   543→    const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   544→    const latest = sortedCps[sortedCps.length - 1] ?? null;
   545→    setLatestCheckpoint(latest);
   546→    setOpenItems(latest?.summary?.openItems ?? []);
   547→
   548→    for (const item of grouped) {
   549→      const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   550→      while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   551→        merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   552→      }
   553→      merged.push(item);
   554→    }
   555→    while (cpIdx < sortedCps.length) merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
   556→    setItems(groupClaudeTurns(merged));
   557→  }
   558→
   559→  // Initial load
   560→  useEffect(() => {
   561→    Promise.all([fetchSession(id), fetchLogEvents(id), fetchSessionCheckpoints(id)])
   562→      .then(([s, logEvs, checkpoints]) => {
   563→        logEventsRef.current = logEvs;
   564→        setSession(s);
   565→        const user = s.gitUserName ?? s.gitUserEmail ?? null;
   566→        const repo = s.repoName ?? null;
