   602→    }, 150);
   603→    return () => clearTimeout(t);
   604→  }, [items, targetLogEventId]);
   605→
   606→  // Step 2: once highlightActive is true (marks rendered, Collapses expanding), scroll to first <mark>
   607→  useEffect(() => {
   608→    if (!highlightActive || targetLogEventId === null) return;
   609→    // Wait for Collapse animations (~200ms) to reach their final layout before measuring
   610→    const t = setTimeout(() => {
   611→      requestAnimationFrame(() => {
   612→        // Resolve UUID for the target logEventId, then find the most precise element
   613→        const uuid = logEventsRef.current.find((le) => le.id === targetLogEventId)?.uuid ?? null;
