  const sum = checkpoint.summary;

  return (
    <Box style={{ padding: "4px 20px 4px 58px" }}>
    <Box style={{ borderLeft: "4px solid var(--mantine-color-teal-6)", borderRadius: 8, overflow: "hidden" }}>
