   234→      const overview = await db.interactionOverview.findUnique({
   235→        where: { sessionId: req.params.id },
   236→      });
   237→      if (!overview) {
   238→        res.status(404).json({ error: "No overview for this session" });
   239→        return;
   240→      }
   241→      const result: OverviewResponse = {
   242→        sessionId: overview.sessionId,
   243→        summary: overview.summary,
   244→        keywords: overview.keywords ? (JSON.parse(overview.keywords) as string[]) : [],
   245→        startedAt: overview.startedAt.toISOString(),
