   319→  // ─── V2 helpers ─────────────────────────────────────────────────────────────
   320→
   321→  type V2Session = {
   322→    summary: {
   323→      intent: string; outcome: string;
   324→      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   325→      frictionItems: { text: string }[];
   326→      repoLearnings: { text: string }[];
