   331→
   332→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   333→    return {
   334→      intent:            summary.intent,
   335→      outcome:           summary.outcome,
   336→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   337→      friction:          summary.frictionItems.map((r) => r.text),
   338→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   339→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   340→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   341→    };
   342→  }
   343→
   344→  const V2_SESSION_INCLUDE = {
   345→    summary: {
   346→      include: {
   347→        openItems:         true,
   348→        frictionItems:     true,
   349→        repoLearnings:     true,
   350→        codeLearnings:     true,
   351→        workflowLearnings: true,
   352→      },
   353→    },
   354→  } as const;
