   494→  // PATCH /api/open-items/:id
   495→  app.patch("/api/open-items/:id", async (req, res) => {
   496→    const id = parseInt(req.params.id, 10);
   497→    const { status, subSessionId } = req.body as { status?: string; subSessionId?: string };
   498→    const allowed = ["open", "in_progress", "complete", "na"];
   499→    if (status !== undefined && !allowed.includes(status)) {
   500→      res.status(400).json({ error: "status must be open, in_progress, or complete" });
   501→      return;
   502→    }
   503→    try {
   504→      const updated = await db.openItem.update({
   505→        where: { id },
   506→        data: {
   507→          ...(status !== undefined ? { status } : {}),
   508→          ...(subSessionId !== undefined ? { subSessionId } : {}),
   509→        },
   510→      });
   511→      res.json({ id: updated.id, status: updated.status, subSessionId: updated.subSessionId });
   512→    } catch (err) {
