   517→  // POST /api/sessions/spawn
   518→  app.post("/api/sessions/spawn", async (req, res) => {
   519→    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   520→    if (!prompt || typeof prompt !== "string") {
   521→      res.status(400).json({ error: "prompt is required" });
   522→      return;
   523→    }
   524→    try {
   525→      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   526→      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   527→      // Pass open item IDs and parent session so the SessionStart hook can link back
   528→      const envParts: string[] = [];
   529→      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   530→      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   531→      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   532→      // Use AppleScript to open a new Terminal window running claude interactively
   533→      const script = [
   534→        `tell application "Terminal"`,
   535→        `  activate`,
   536→        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   537→        `end tell`,
   538→      ].join("\n");
   539→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   540→      // Mark selected open items as in_progress
   541→      if (openItemIds?.length) {
   542→        await db.openItem.updateMany({
   543→          where: { id: { in: openItemIds } },
   544→          data: { status: "in_progress" },
   545→        });
   546→      }
   547→      res.json({ started: true });
   548→    } catch (err) {
   549→      res.status(500).json({ error: String(err) });
   550→    }
   551→  });
   552→
   553→  // GET /api/search?q=TEXT[&limit=N]
   554→  app.get("/api/search", async (req, res) => {
   555→    const q     = typeof req.query.q     === "string" ? req.query.q.trim()         : "";
   556→    const limit = typeof req.query.limit === "string" ? parseInt(req.query.limit)  : 50;
   557→    if (!q) { res.status(400).json({ error: "q is required" }); return; }
   558→    try {
   559→      const results = await searchLogContent(db, q, Math.min(limit, 200));
   560→      const sessionIds = [...new Set(results.map((r) => r.sessionId))];
   561→      const sessionMetas = sessionIds.length > 0
   562→        ? await db.checkpointSessionMetadata.findMany({
   563→            where: { sessionId: { in: sessionIds } },
   564→            select: { sessionId: true, checkpointId: true },
   565→            distinct: ["sessionId"],
   566→            orderBy: { createdAt: "desc" },
   567→          })
   568→        : [];
   569→      const cpIds = [...new Set(sessionMetas.map((m) => m.checkpointId))];
   570→      const cpUsers = cpIds.length > 0
   571→        ? await db.checkpointMetadata.findMany({
   572→            where: { checkpointId: { in: cpIds } },
   573→            select: { checkpointId: true, gitUserName: true, gitUserEmail: true },
   574→          })
   575→        : [];
   576→      const cpUserMap = new Map(cpUsers.map((r) => [r.checkpointId, r]));
   577→      const sessionUserMap = new Map(sessionMetas.map((m) => {
   578→        const u = cpUserMap.get(m.checkpointId);
   579→        return [m.sessionId, { gitUserName: u?.gitUserName ?? null, gitUserEmail: u?.gitUserEmail ?? null }];
   580→      }));
   581→      res.json(results.map((r) => {
   582→        const u = sessionUserMap.get(r.sessionId);
   583→        return { ...r, gitUserName: u?.gitUserName ?? gitUser.name, gitUserEmail: u?.gitUserEmail ?? gitUser.email };
   584→      }));
   585→    } catch (err) {
   586→      // FTS5 MATCH errors (bad syntax) come back as exceptions
   587→      res.status(400).json({ error: String(err) });
   588→    }
   589→  });
   590→
   591→  // Create HTTP server and attach WebSocket server (shared port)
   592→  const httpServer = createServer(app);
   593→  const wss = new WebSocketServer({ server: httpServer });
   594→
   595→  // WebSocket change detection — poll every 2s, broadcast on new log events, checkpoints, or shadow sessions
   596→  let lastMaxLogEventId: number | null = null;
   597→  let lastMaxCheckpointId: number | null = null;
   598→  let lastMaxShadowSessionId: number | null = null;
   599→  const broadcast = () => {
   600→    const message = JSON.stringify({ type: "sessions_updated" });
   601→    for (const client of wss.clients) {
   602→      if (client.readyState === WebSocket.OPEN) {
   603→        client.send(message);
   604→      }
   605→    }
   606→  };
   607→  const poller = setInterval(async () => {
   608→    try {
   609→      const [latestLogEvent, latestCheckpoint, latestShadow] = await Promise.all([
   610→        db.logEvent.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   611→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   612→        db.shadowSession.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   613→      ]);
   614→      const curLogEvent   = latestLogEvent?.id   ?? null;
   615→      const curCheckpoint = latestCheckpoint?.id ?? null;
   616→      const curShadow     = latestShadow?.id     ?? null;
   617→      if (curLogEvent !== lastMaxLogEventId || curCheckpoint !== lastMaxCheckpointId || curShadow !== lastMaxShadowSessionId) {
   618→        lastMaxLogEventId   = curLogEvent;
   619→        lastMaxCheckpointId = curCheckpoint;
   620→        lastMaxShadowSessionId = curShadow;
   621→        broadcast();
   622→      }
   623→    } catch {
   624→      // Non-fatal polling error — keep running
   625→    }
   626→  }, 2000);
   627→
   628→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   629→
   630→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   631→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   632→
   633→  if (repoDir) {
   634→    const WORKTREE_PATH = join(repoDir, ".gossamer", "checkpoints");
   635→    mkdirSync(join(repoDir, ".gossamer"), { recursive: true });
   636→
   637→    // Ensure worktree exists (reuse across restarts)
   638→    if (!existsSync(WORKTREE_PATH)) {
   639→      try {
   640→        // Prune stale worktree registration first, then re-add
   641→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   642→        execSync(
   643→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   644→          { stdio: "pipe" },
   645→        );
   646→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   647→      } catch (err) {
   648→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   649→      }
   650→    }
   651→
   652→    const runIndex = async () => {
   653→      if (!existsSync(WORKTREE_PATH)) return;
   654→      try {
   655→        // Fetch from remote, then reset to the remote tracking ref so new commits
   656→        // pushed by teammates are actually applied to the worktree.
   657→        // Falls back to the local branch tip if the remote is unavailable.
   658→        try {
   659→          execSync(
   660→            `git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`,
   661→            { stdio: "pipe" },
   662→          );
   663→          execSync(
   664→            `git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard origin/${CHECKPOINT_BRANCH}`,
   665→            { stdio: "pipe" },
   666→          );
   667→        } catch {
   668→          // Remote unavailable — fall back to local branch tip
   669→          try {
   670→            execSync(
   671→              `git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard ${CHECKPOINT_BRANCH}`,
   672→              { stdio: "pipe" },
   673→            );
   674→          } catch { /* non-fatal */ }
   675→        }
   676→      } catch { /* non-fatal */ }
   677→      try {
   678→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   679→        if (checkpoints > 0) {
   680→          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   681→          broadcast();
   682→        }
   683→      } catch { /* non-fatal */ }
   684→    };
   685→
   686→    void runIndex();
   687→    checkpointPoller = setInterval(runIndex, 30_000);
   688→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   689→  }
   690→
   691→  // ── Shadow branch indexer ──────────────────────────────────────────────────
   692→
   693→  let shadowPoller: ReturnType<typeof setInterval> | null = null;
   694→
   695→  if (repoDir) {
   696→    const runShadowIndex = async () => {
   697→      try {
   698→        const { sessions } = await indexAllShadowBranches(db, repoDir);
   699→        if (sessions > 0) broadcast();
   700→      } catch { /* non-fatal */ }
   701→    };
   702→
   703→    void runShadowIndex();
   704→    shadowPoller = setInterval(runShadowIndex, 5_000);
   705→    process.stderr.write(`shadow indexer: polling every 5s (repo: ${repoDir})\n`);
   706→  }
   707→
   708→  // Graceful shutdown
   709→  const shutdown = () => {
   710→    clearInterval(poller);
   711→    if (checkpointPoller) clearInterval(checkpointPoller);
   712→    if (shadowPoller) clearInterval(shadowPoller);
   713→    httpServer.close();
   714→    process.exit(0);
   715→  };
   716→  process.on("SIGINT", shutdown);
   717→  process.on("SIGTERM", shutdown);
   718→
   719→  await new Promise<void>((resolve) => {
   720→    httpServer.listen(port, () => {
   721→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   722→      resolve();
   723→    });
   724→  });
   725→}
